     1→/* Variables */
     2→:root {
     3→  --bg-primary: #0a0a0f;
     4→  --bg-secondary: #12121a;
     5→  --bg-card: #1a1a24;
     6→  --bg-elevated: #22222e;
     7→  
     8→  --text-primary: #f4f4f5;
     9→  --text-secondary: #a1a1aa;
    10→  --text-muted: #71717a;
    11→  
    12→  --accent-primary: #10b981;
    13→  --accent-secondary: #34d399;
    14→  --accent-gradient: linear-gradient(135deg, #10b981 0%, #06b6d4 100%);
    15→  
    16→  --border-color: #27272a;
    17→  --border-light: #3f3f46;
    18→  
    19→  --font-display: 'Space Grotesk', sans-serif;
    20→  --font-body: 'Inter', sans-serif;
    21→  
    22→  --radius-sm: 6px;
    23→  --radius-md: 12px;
    24→  --radius-lg: 20px;
    25→  --radius-full: 9999px;
    26→  
    27→  --shadow-sm: 0 2px 8px rgba(0, 0, 0, 0.3);
    28→  --shadow-md: 0 4px 20px rgba(0, 0, 0, 0.4);
    29→  --shadow-lg: 0 8px 40px rgba(0, 0, 0, 0.5);
    30→  --shadow-glow: 0 0 40px rgba(16, 185, 129, 0.2);
    31→}
    32→
    33→/* Reset */
    34→*, *::before, *::after {
    35→  box-sizing: border-box;
    36→  margin: 0;
    37→  padding: 0;
    38→}
    39→
    40→html {
    41→  scroll-behavior: smooth;
    42→}
    43→
    44→body {
    45→  font-family: var(--font-body);
    46→  background: var(--bg-primary);
    47→  color: var(--text-primary);
    48→  line-height: 1.6;
    49→  -webkit-font-smoothing: antialiased;
    50→}
    51→
    52→a {
    53→  color: inherit;
    54→  text-decoration: none;
    55→}
    56→
    57→ul {
    58→  list-style: none;
    59→}
    60→
    61→/* Utility Classes */
    62→.text-gradient {
    63→  background: var(--accent-gradient);
    64→  -webkit-background-clip: text;
    65→  -webkit-text-fill-color: transparent;
    66→  background-clip: text;
    67→}
    68→
    69→/* Buttons */
    70→.btn {
    71→  display: inline-flex;
    72→  align-items: center;
    73→  justify-content: center;
    74→  gap: 8px;
    75→  padding: 12px 24px;
    76→  font-family: var(--font-display);
    77→  font-weight: 500;
    78→  font-size: 15px;
    79→  border-radius: var(--radius-full);
    80→  border: none;
    81→  cursor: pointer;
    82→  transition: all 0.2s ease;
    83→}
    84→
    85→.btn-primary {
    86→  background: var(--accent-gradient);
    87→  color: #000;
    88→  box-shadow: var(--shadow-glow);
    89→}
    90→
    91→.btn-primary:hover {
    92→  transform: translateY(-2px);
    93→  box-shadow: 0 0 60px rgba(16, 185, 129, 0.3);
    94→}
    95→
    96→.btn-ghost {
    97→  background: transparent;
    98→  color: var(--text-primary);
    99→  border: 1px solid var(--border-light);
   100→}
   101→
   102→.btn-ghost:hover {
   103→  background: var(--bg-elevated);
   104→  border-color: var(--accent-primary);
   105→}
   106→
   107→.btn-large {
   108→  padding: 16px 32px;
   109→  font-size: 16px;
   110→}
   111→
   112→.btn-full {
   113→  width: 100%;
   114→}
   115→
   116→.btn-outline-danger {
   117→  background: transparent;
   118→  color: #ef4444;
   119→  border: 1px solid #ef4444;
   120→}
   121→
   122→.btn-outline-danger:hover {
   123→  background: rgba(239, 68, 68, 0.1);
   124→  border-color: #dc2626;
   125→}
   126→
   127→/* Navigation */
   128→.nav {
   129→  position: fixed;
   130→  top: 0;
   131→  left: 0;
   132→  right: 0;
