   435→
   436→.feature-card p {
   437→  font-size: 15px;
   438→  color: var(--text-secondary);
   439→  line-height: 1.6;
   440→}
   441→
   442→/* How It Works */
   443→.how-it-works {
   444→  padding: 100px 24px;
   445→  background: var(--bg-secondary);
   446→}
   447→
   448→.steps {
   449→  max-width: 800px;
   450→  margin: 0 auto;
