   637→
   638→/* OmniScore Styles */
   639→.omniscore-preview {
   640→  background: linear-gradient(135deg, var(--bg-card) 0%, #1a1a2e 100%);
   641→}
   642→
   643→.omniscore-display {
   644→  display: flex;
