file.content:
/* Interview Layout */
.interview-layout {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
}

.interview-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 16px 32px;
  background: var(--bg-secondary);
  border-bottom: 1px solid var(--border-color);
}

.back-btn {
  display: flex;
  align-items: center;
  gap: 8px;
  color: var(--text-secondary);
  font-size: 14px;
  transition: color 0.2s;
}

.back-btn:hover {
  color: var(--text-primary);
}

.interview-progress {
  display: flex;
  align-items: center;
  gap: 16px;
}

#progress-text {
  font-size: 14px;
  color: var(--text-muted);
}

.progress-bar {
  width: 200px;
  height: 6px;
  background: var(--bg-elevated);
  border-radius: var(--radius-full);
  overflow: hidden;
}

.progress-fill {
  height: 100%;
  background: var(--accent-gradient);
  transition: width 0.3s ease;
}

.timer {
  font-family: var(--font-display);
  font-size: 18px;
  font-weight: 600;
  color: var(--accent-primary);
}

/* Screens */
.screen {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 40px;
}

/* Setup Screen */
.setup-container {
  max-width: 560px;
  width: 100%;
}

.setup-container h1 {
  font-family: var(--font-display);
  font-size: 36px;
  font-weight: 700;
  margin-bottom: 12px;
  text-align: center;
}

.setup-container > p {
  color: var(--text-secondary);
  text-align: center;
  margin-bottom: 40px;
}

.setup-container .form-group {
  margin-bottom: 24px;
}

.setup-container label {
  display: block;
  font-size: 14px;
  font-weight: 500;
  margin-bottom: 8px;
  color: var(--text-secondary);
}

.setup-container input,
.setup-container textarea,
.setup-container select {
  width: 100%;
  padding: 14px 16px;
  background: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-md);
  color: var(--text-primary);
  font-size: 15px;
  font-family: var(--font-body);
  transition: border-color 0.2s, box-shadow 0.2s;
}

.setup-container input:focus,
.setup-container textarea:focus,
.setup-container select:focus {
  outline: none;
  border-color: var(--accent-primary);
  box-shadow: 0 0 0 3px rgba(16, 185, 129, 0.1);
}

.setup-container textarea {
  resize: vertical;
}

/* Interview Screen */
.interview-container {
  max-width: 900px;
  width: 100%;
  display: flex;
  flex-direction: column;
  gap: 32px;
}

.question-section {
  text-align: center;
}

.ai-interviewer {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 8px 16px;
  background: var(--bg-card);
  border-radius: var(--radius-full);
  margin-bottom: 20px;
}

.ai-avatar {
  font-size: 20px;
}

.ai-interviewer span {
  font-size: 13px;
  font-weight: 500;
  color: var(--text-muted);
}

.question-card {
  background: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  padding: 32px;
  text-align: left;
}

.question-label {
  display: inline-block;
  padding: 6px 12px;
  background: rgba(16, 185, 129, 0.1);
  border-radius: var(--radius-full);
  font-size: 12px;
  font-weight: 600;
  color: var(--accent-primary);
  text-transform: uppercase;
  margin-bottom: 16px;
}

.question-text {
  font-size: 20px;
  line-height: 1.6;
}

/* Response Section */
.response-section {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 24px;
}

.video-container {
  position: relative;
  background: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  overflow: hidden;
  aspect-ratio: 4/3;
}

#video-preview {
  width: 100%;
  height: 100%;
  object-fit: cover;
}

.video-overlay {
  position: absolute;
  inset: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  background: rgba(0, 0, 0, 0.7);
  text-align: center;
}

.video-overlay p {
  font-size: 16px;
  margin-bottom: 8px;
}

.video-overlay small {
  font-size: 12px;
  color: var(--text-muted);
}

.response-input {
  display: flex;
  flex-direction: column;
}

.response-input label {
  font-size: 14px;
  font-weight: 500;
  margin-bottom: 8px;
  color: var(--text-secondary);
}

.response-input textarea {
  flex: 1;
  padding: 16px;
  background: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  color: var(--text-primary);
  font-size: 15px;
  font-family: var(--font-body);
  resize: none;
}

.response-input textarea:focus {
  outline: none;
  border-color: var(--accent-primary);
}

.response-controls {
  grid-column: 1 / -1;
  display: flex;
  justify-content: flex-end;
  gap: 16px;
}

/* Feedback Screen */
.feedback-container {
  max-width: 600px;
  width: 100%;
}

.feedback-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 32px;
}

.feedback-header h2 {
  font-family: var(--font-display);
  font-size: 24px;
  font-weight: 700;
}

.score-badge {
  padding: 8px 20px;
  background: var(--accent-gradient);
  border-radius: var(--radius-full);
  font-family: var(--font-display);
  font-size: 20px;
  font-weight: 700;
  color: #000;
}

.feedback-section {
  background: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  padding: 24px;
  margin-bottom: 20px;
}

.feedback-section h3 {
  font-family: var(--font-display);
  font-size: 16px;
  font-weight: 600;
  margin-bottom: 16px;
}

.feedback-section ul {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.feedback-section li {
  padding-left: 20px;
  position: relative;
  color: var(--text-secondary);
  line-height: 1.5;
}

.feedback-section li::before {
  content: '•';
  position: absolute;
  left: 0;
  color: var(--accent-primary);
}

.feedback-section p {
  color: var(--text-secondary);
  line-height: 1.7;
}

/* Results Screen */
.results-container {
  max-width: 700px;
  width: 100%;
}

.results-header {
  text-align: center;
  margin-bottom: 40px;
}

.results-header h1 {
  font-family: var(--font-display);
  font-size: 36px;
  font-weight: 700;
  margin-bottom: 8px;
}

.results-header p {
  color: var(--text-secondary);
}

.overall-score-card {
  background: var(--bg-card);
  border: 1px solid var(--accent-primary);
  border-radius: var(--radius-lg);
  padding: 32px;
  display: flex;
  align-items: center;
  gap: 32px;
  margin-bottom: 32px;
  box-shadow: var(--shadow-glow);
}

.score-circle {
  width: 120px;
  height: 120px;
  border-radius: 50%;
  background: var(--accent-gradient);
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

.score-value {
  font-family: var(--font-display);
  font-size: 48px;
  font-weight: 700;
  color: #000;
  line-height: 1;
}

.score-max {
  font-size: 18px;
  color: rgba(0, 0, 0, 0.6);
}

.score-info {
  flex: 1;
}

.readiness-badge {
  display: inline-block;
  padding: 6px 16px;
  background: var(--bg-elevated);
  border-radius: var(--radius-full);
  font-size: 14px;
  font-weight: 600;
  margin-bottom: 12px;
}

.readiness-badge.ready {
  background: rgba(16, 185, 129, 0.2);
  color: var(--accent-primary);
}

.readiness-badge.almost {
  background: rgba(245, 158, 11, 0.2);
  color: #f59e0b;
}

.readiness-badge.needs-work {
  background: rgba(239, 68, 68, 0.2);
  color: #ef4444;
}

.score-info p {
  color: var(--text-secondary);
  line-height: 1.6;
}

.results-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 20px;
  margin-bottom: 20px;
}

.results-section {
  background: var(--bg-card);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  padding: 24px;
  margin-bottom: 20px;
}

.results-section h3 {
  font-family: var(--font-display);
  font-size: 16px;
  font-weight: 600;
  margin-bottom: 16px;
}

.results-section ul {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.results-section li {
  padding-left: 20px;
  position: relative;
  color: var(--text-secondary);
  line-height: 1.5;
}

.results-section li::before {
  content: '•';
  position: absolute;
  left: 0;
  color: var(--accent-primary);
}

.results-actions {
  display: flex;
  gap: 16px;
  justify-content: center;
}

/* Loading Overlay */
.loading-overlay {
  position: fixed;
  inset: 0;
  background: rgba(10, 10, 15, 0.9);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 100;
}

.loading-content {
  text-align: center;
}

.spinner-large {
  width: 48px;
  height: 48px;
  border: 4px solid var(--border-color);
  border-top-color: var(--accent-primary);
  border-radius: 50%;
  animation: spin 1s linear infinite;
  margin: 0 auto 20px;
}

.loading-content p {
  font-size: 16px;
  color: var(--text-secondary);
}

/* Responsive */
@media (max-width: 768px) {
  .interview-header {
    padding: 12px 16px;
  }

  .screen {
    padding: 20px;
  }

  .response-section {
    grid-template-columns: 1fr;
  }

  .video-container {
    aspect-ratio: 16/9;
  }

  .overall-score-card {
    flex-direction: column;
    text-align: center;
  }

  .results-grid {
    grid-template-columns: 1fr;
  }

  .results-actions {
    flex-direction: column;
  }
}

